window.SECAI = window.SECAI || {}; SECAI.questions = SECAI.questions || [];
SECAI.questions.push(
  { id:"D3-001", domain:3, obj:"3.1", diff:"easy", q:"A SOC analyst wants an AI-enabled tool that reduces the manual effort of reviewing thousands of daily SIEM alerts by automatically grouping, summarizing, and prioritizing them. Which capability is the analyst primarily relying on?", options:["AI-driven alert triage and summarization","Manual signature authoring","Physical security badge auditing","Spreadsheet-based ticket counting"], answer:0, explain:"<strong>AI-driven alert triage and summarization</strong> lets the tool cluster, prioritize, and condense large alert volumes so analysts focus on the most important events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual signature authoring</b>: this is human work that AI is meant to reduce, not the triage capability described.</span><span class='qd'><b>Physical security badge auditing</b>: this concerns physical access control, unrelated to SIEM alert handling.</span><span class='qd'><b>Spreadsheet-based ticket counting</b>: this is a manual tallying activity, not AI-enabled triage.</span>" },
  { id:"D3-002", domain:3, obj:"3.1", diff:"medium", q:"An AI plug-in inside VS Code suggests fixes for bugs, completes code, and explains functions to junior developers as they write detection scripts. Which type of tool is described?", options:["A no-code website builder","An AI-enabled IDE plug-in such as Copilot","A network packet sniffer","A hardware security module"], answer:1, explain:"<strong>An AI-enabled IDE plug-in such as Copilot</strong> provides code completion, generation, refactoring, bug detection, and explanations directly inside the IDE.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A no-code website builder</b>: tools like Wix produce HTML visually and are not IDE coding assistants.</span><span class='qd'><b>A network packet sniffer</b>: this captures traffic and does not assist with writing code.</span><span class='qd'><b>A hardware security module</b>: an HSM manages cryptographic keys, not code suggestions.</span>" },
  { id:"D3-003", domain:3, obj:"3.1", diff:"medium", q:"A security engineer uses an AI tool that flags errors, bugs, and style inconsistencies in a Python script but does not specifically hunt for injection or XSS vulnerabilities. Which activity best describes this?", options:["Penetration testing","Dynamic application security testing","Code linting","Threat modeling"], answer:2, explain:"<strong>Code linting</strong> focuses on code quality, style, and catching errors and inconsistencies rather than targeting specific security vulnerabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Dynamic application security testing</b>: DAST tests a running application for security flaws, not static style issues.</span><span class='qd'><b>Penetration testing</b>: this actively exploits a system rather than reviewing code style.</span><span class='qd'><b>Threat modeling</b>: this analyzes design-level threats, not code syntax and style.</span>" },
  { id:"D3-004", domain:3, obj:"3.1", diff:"medium", q:"A development team needs an AI-assisted scan that specifically targets injection attacks, cross-site scripting, and broken authentication in their source code before compilation. Which technique fits best?", options:["Code linting for style","Deepfake generation","Anomaly-based fraud detection","Static Application Security Testing (SAST)"], answer:3, explain:"<strong>Static Application Security Testing (SAST)</strong> analyzes source code for specific security vulnerabilities like injection, XSS, and broken authentication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Code linting for style</b>: linting focuses on coding standards and quality, not security vulnerability classes.</span><span class='qd'><b>Anomaly-based fraud detection</b>: this detects abnormal transactions, not code vulnerabilities.</span><span class='qd'><b>Deepfake generation</b>: this creates synthetic media and is an attack technique, not a code scan.</span>" },
  { id:"D3-005", domain:3, obj:"3.1", diff:"easy", q:"A credit card processor trains an AI system to flag a transaction in New York and another in Tokyo five minutes apart as suspicious because the travel would be physically impossible. Which AI capability is this?", options:["Code refactoring","Anomaly detection for fraud","Software bill of materials generation","Voice cloning"], answer:1, explain:"<strong>Anomaly detection for fraud</strong> compares transaction time and location against normal patterns to flag physically impossible activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Code refactoring</b>: this restructures code and has nothing to do with transaction analysis.</span><span class='qd'><b>Software bill of materials generation</b>: an SBOM lists software components, not fraud signals.</span><span class='qd'><b>Voice cloning</b>: this synthesizes speech and is an attack technique, not fraud detection.</span>" },
  { id:"D3-006", domain:3, obj:"3.1", diff:"medium", q:"A SIEM platform compares current network traffic flows against an established baseline of normal activity and raises an alert when behavior deviates. Which detection method is in use?", options:["Signature matching","Honeypot deception","Anomaly detection","Composition analysis"], answer:2, explain:"<strong>Anomaly detection</strong> evaluates current traffic against baselines of normal activity and alerts on deviations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signature matching</b>: this looks for predefined known patterns, not deviations from a baseline.</span><span class='qd'><b>Honeypot deception</b>: a honeypot is a decoy system, not a traffic-baseline comparison.</span><span class='qd'><b>Composition analysis</b>: SCA reviews third-party components, not network traffic baselines.</span>" },
  { id:"D3-007", domain:3, obj:"3.1", diff:"easy", q:"An AV-style detection engine scans files for specific bits of code that match predefined patterns of known malicious activity. Which technique is this?", options:["Anomaly detection","Regression testing","Zero-shot learning","Signature matching"], answer:3, explain:"<strong>Signature matching</strong> uses predefined patterns to identify known malicious activity, similar to antivirus signature scanning.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Anomaly detection</b>: this finds deviations from a baseline, not matches to known signatures.</span><span class='qd'><b>Zero-shot learning</b>: this recognizes new unseen objects, the opposite of matching known patterns.</span><span class='qd'><b>Regression testing</b>: this verifies that code changes do not break functionality.</span>" },
  { id:"D3-008", domain:3, obj:"3.1", diff:"hard", q:"A vulnerability management team wants their AI tool to enrich findings by pulling adversarial techniques that specifically target machine learning systems. Which knowledge base is most appropriate?", options:["MITRE ATLAS","The OSI model","The Wix template library","The HVAC control schema"], answer:0, explain:"<strong>MITRE ATLAS</strong> catalogs adversarial threats, vulnerabilities, and attack techniques targeting AI and machine learning systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The OSI model</b>: this is a networking reference model, not an adversarial ML threat database.</span><span class='qd'><b>The Wix template library</b>: this provides website templates, not threat intelligence.</span><span class='qd'><b>The HVAC control schema</b>: this relates to building climate control, not security.</span>" },
  { id:"D3-009", domain:3, obj:"3.1", diff:"medium", q:"During an automated vulnerability assessment, an AI tool regularly queries MITRE's CVE database and NIST's NVD to identify the impact and exploitation level of findings. What is the primary benefit?", options:["It eliminates the need for any human review","It generates deepfake audio of executives","It enriches findings with authoritative impact and exploitation data","It replaces the organization's firewall"], answer:2, explain:"<strong>It enriches findings with authoritative impact and exploitation data</strong> by cross-referencing CVE and NVD entries to properly prioritize vulnerabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need for any human review</b>: AI output should still be reviewed for auditability and accountability.</span><span class='qd'><b>It generates deepfake audio of executives</b>: that is an attack technique, not vulnerability enrichment.</span><span class='qd'><b>It replaces the organization's firewall</b>: querying databases does not substitute for a firewall control.</span>" },
  { id:"D3-010", domain:3, obj:"3.1", diff:"medium", q:"An NMAP scan reveals open ports and service versions, and the AI penetration testing platform then recommends specific exploits likely to work against those services. Which capability is demonstrated?", options:["Deepfake synthesis","SBOM auditing","Static linting","Adaptive AI-enabled penetration testing"], answer:3, explain:"<strong>Adaptive AI-enabled penetration testing</strong> uses scan data to recommend targeted exploits and modify the attack as conditions change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deepfake synthesis</b>: this creates fake media and is unrelated to exploit selection.</span><span class='qd'><b>Static linting</b>: linting reviews code quality, not live network exploitation.</span><span class='qd'><b>SBOM auditing</b>: this inventories software components, not exploit recommendations.</span>" },
  { id:"D3-011", domain:3, obj:"3.1", diff:"hard", q:"A penetration tester is mid-test when the target's security team closes the port being exploited. The AI platform then recommends an alternate attack method automatically. What property of the platform enables this?", options:["It adapts its approach in real time based on the target's responses","It is a static rule list that never changes","It only runs once and stops","It relies solely on manual analyst input"], answer:0, explain:"<strong>It adapts its approach in real time based on the target's responses</strong>, recommending alternate methods when defenders react during a test.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is a static rule list that never changes</b>: a static list could not respond to a closed port dynamically.</span><span class='qd'><b>It only runs once and stops</b>: the scenario shows continued adaptation, not a single pass.</span><span class='qd'><b>It relies solely on manual analyst input</b>: the platform itself recommends the new method automatically.</span>" },
  { id:"D3-012", domain:3, obj:"3.1", diff:"medium", q:"A defensive team uses an AI threat modeling platform that applies STRIDE and ATLAS frameworks to analyze configurations and predict attacks unique to their environment. What is the main outcome?", options:["Generation of phishing emails","Environment-specific threat models and security recommendations","Automatic deletion of all logs","Cloning of an executive's voice"], answer:1, explain:"<strong>Environment-specific threat models and security recommendations</strong> result from applying STRIDE and ATLAS to the organization's data and configurations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generation of phishing emails</b>: that is an offensive misuse, not defensive threat modeling.</span><span class='qd'><b>Automatic deletion of all logs</b>: threat modeling produces analysis, it does not destroy logs.</span><span class='qd'><b>Cloning of an executive's voice</b>: voice cloning is a deepfake attack technique.</span>" },
  { id:"D3-013", domain:3, obj:"3.1", diff:"medium", q:"An analyst asks Microsoft Sentinel's Security Copilot, in plain English, to investigate and summarize a suspicious incident. Which AI capability does Copilot primarily provide?", options:["A GAN for image generation","A physical access control gate","A no-code spreadsheet template","A natural language interface for investigation and incident summarization"], answer:3, explain:"<strong>A natural language interface for investigation and incident summarization</strong> describes Security Copilot working alongside Sentinel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A physical access control gate</b>: Copilot is software, not a physical barrier.</span><span class='qd'><b>A no-code spreadsheet template</b>: Copilot provides an AI investigation interface, not a spreadsheet.</span><span class='qd'><b>A GAN for image generation</b>: a GAN generates media and is not an incident investigation assistant.</span>" },
  { id:"D3-014", domain:3, obj:"3.1", diff:"hard", q:"A team deploys multiple AI agents that must share memory, goals, and intermediate results across a workflow without heavy custom integration. Which emerging standard supports this?", options:["Model Context Protocol (MCP)","Search Processing Language (SPL)","Software Bill of Materials (SBOM)","Generative Adversarial Network (GAN)"], answer:0, explain:"<strong>Model Context Protocol (MCP)</strong> lets AI agents and tools share context and state across workflows in a structured, interoperable way.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Search Processing Language (SPL)</b>: SPL is Splunk's query language, not an agent context protocol.</span><span class='qd'><b>Software Bill of Materials (SBOM)</b>: an SBOM lists components, it does not share runtime context.</span><span class='qd'><b>Generative Adversarial Network (GAN)</b>: a GAN is a model architecture, not an interoperability standard.</span>" },
  { id:"D3-015", domain:3, obj:"3.1", diff:"hard", q:"A security architect is concerned that adopting MCP across agents could broaden the attack surface. Which risk is most directly associated with MCP-enabled workflows?", options:["Excessive HVAC energy use","Context leakage of sensitive data passed between agents","Loss of physical badge inventory","Increased printer toner consumption"], answer:1, explain:"<strong>Context leakage of sensitive data passed between agents</strong> is the key MCP risk, since prompts, inputs, or weights moving between agents could be intercepted without controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive HVAC energy use</b>: this is unrelated to data sharing between AI agents.</span><span class='qd'><b>Loss of physical badge inventory</b>: that is a physical asset issue, not an MCP data risk.</span><span class='qd'><b>Increased printer toner consumption</b>: this has no connection to AI context sharing.</span>" },
  { id:"D3-016", domain:3, obj:"3.1", diff:"medium", q:"To mitigate the context leakage risk of an MCP-enabled multi-agent pipeline, which combination of controls is most recommended?", options:["Removing authentication entirely","Disabling all logging permanently","Access controls, logging, and encryption","Sharing system prompts publicly"], answer:2, explain:"<strong>Access controls, logging, and encryption</strong> are the recommended controls when deploying MCP-enabled workflows to prevent interception or misuse of shared context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disabling all logging permanently</b>: removing logging eliminates the auditability needed for accountability.</span><span class='qd'><b>Removing authentication entirely</b>: this would expand, not reduce, the attack surface.</span><span class='qd'><b>Sharing system prompts publicly</b>: exposing prompts increases leakage rather than mitigating it.</span>" },
  { id:"D3-017", domain:3, obj:"3.1", diff:"easy", q:"A junior analyst relies on a chatbot trained on poor-quality data, and it produces a fabricated, confident-sounding incident procedure. What is this AI failure called?", options:["A hallucination","A honeypot","A baseline","A signature"], answer:0, explain:"<strong>A hallucination</strong> occurs when a tool not trained on accurate data produces incorrect or fabricated output presented confidently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A honeypot</b>: a honeypot is a decoy system, not a fabricated AI output.</span><span class='qd'><b>A baseline</b>: a baseline is a reference of normal activity, not an error.</span><span class='qd'><b>A signature</b>: a signature is a known malicious pattern, not a fabrication.</span>" },
  { id:"D3-018", domain:3, obj:"3.1", diff:"medium", q:"Before deploying any AI security tool to production, what does the source material recommend as standard procedure to manage hallucination and incorrect-command risk?", options:["Deploy immediately to production with no testing","Careful monitoring and controlled-environment testing","Disable all human oversight","Remove the tool from version control"], answer:1, explain:"<strong>Careful monitoring and controlled-environment testing</strong> should be standard procedure before implementing AI tools in production.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deploy immediately to production with no testing</b>: this ignores the recommended controlled testing step.</span><span class='qd'><b>Disable all human oversight</b>: oversight is needed, not removal.</span><span class='qd'><b>Remove the tool from version control</b>: this does not address tool reliability and is unrelated.</span>" },
  { id:"D3-019", domain:3, obj:"3.1", diff:"medium", q:"A security team wants AI assistance generating complex Git commands from natural language directly at the command line. Which type of tool fits?", options:["A GAN discriminator","A hardware firewall","A CLI plug-in such as aicommits","A physical token"], answer:2, explain:"<strong>A CLI plug-in such as aicommits</strong> brings AI command generation and explanation to the command-line interface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hardware firewall</b>: this filters traffic and does not generate CLI commands.</span><span class='qd'><b>A GAN discriminator</b>: this evaluates generated content, not shell commands.</span><span class='qd'><b>A physical token</b>: a token is used for authentication, not command generation.</span>" },
  { id:"D3-020", domain:3, obj:"3.1", diff:"medium", q:"An organization wants its SIEM to use natural language processing to draft detection alerts by querying machine-generated logs with a query language and feeding results into anomaly detection. In Splunk, which query language performs the search and filtering?", options:["Sender Policy Framework (SPF)","Hypertext Markup Language (HTML)","Structured Threat Information Expression (STIX)","Search Processing Language (SPL)"], answer:3, explain:"<strong>Search Processing Language (SPL)</strong> is Splunk's language used to search, filter, and analyze machine-generated data before feeding results into predictive modules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hypertext Markup Language (HTML)</b>: HTML structures web pages, it is not a log query language.</span><span class='qd'><b>Structured Threat Information Expression (STIX)</b>: STIX is a threat-sharing format, not a search language.</span><span class='qd'><b>Sender Policy Framework (SPF)</b>: SPF validates email senders, not log searching.</span>" },
  { id:"D3-021", domain:3, obj:"3.1", diff:"easy", q:"A manager wants AI to detect an incident, identify indicators of compromise, collect logs and evidence, and automatically draft an initial report to senior leadership. What is the primary benefit to the organization?", options:["Permanent elimination of all firewalls","Faster internal and external communications and rapid response","Guaranteed zero false positives forever","Replacement of the entire security team"], answer:1, explain:"<strong>Faster internal and external communications and rapid response</strong> result when AI automates detection, evidence collection, and initial reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanent elimination of all firewalls</b>: AI reporting does not remove the need for network controls.</span><span class='qd'><b>Guaranteed zero false positives forever</b>: AI reduces but cannot guarantee elimination of false positives.</span><span class='qd'><b>Replacement of the entire security team</b>: AI assists analysts rather than replacing them entirely.</span>" },
  { id:"D3-022", domain:3, obj:"3.1", diff:"hard", q:"An LLM-based code analysis tool goes beyond style checks to find security flaws and provide contextual help to developers. How does this differ from traditional linting?", options:["It is identical to linting in every way","It only checks spelling in comments","It targets security flaws and context, while linting focuses on code quality and standards","It only counts lines of code"], answer:2, explain:"<strong>It targets security flaws and context, while linting focuses on code quality and standards</strong> distinguishes LLM-driven security analysis from linting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is identical to linting in every way</b>: the two have different focuses, security versus quality.</span><span class='qd'><b>It only checks spelling in comments</b>: this trivializes the security analysis the LLM performs.</span><span class='qd'><b>It only counts lines of code</b>: line counting is a metric, not vulnerability analysis.</span>" },
  { id:"D3-023", domain:3, obj:"3.1", diff:"medium", q:"A SIEM personal assistant examines log files, summarizes them to identify an incident, and automatically creates an incident case in a case management application. Which benefit is highlighted?", options:["Manual rewriting of every log by hand","Generation of deepfake video","Physical destruction of evidence","Streamlined detection-to-case-management workflow"], answer:3, explain:"<strong>Streamlined detection-to-case-management workflow</strong> describes the assistant summarizing logs and automatically opening a case.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generation of deepfake video</b>: that is an offensive technique, not log summarization.</span><span class='qd'><b>Physical destruction of evidence</b>: the assistant collects evidence, it does not destroy it.</span><span class='qd'><b>Manual rewriting of every log by hand</b>: automation removes such manual effort.</span>" },
  { id:"D3-024", domain:3, obj:"3.1", diff:"medium", q:"An incident management platform analyzes the timeline, responses, and controls used during an incident and then suggests configuration changes, beneficial training, and new controls. What is this output called?", options:["Recommendations for improvement","A deepfake script","A denial-of-service payload","A GAN training set"], answer:0, explain:"<strong>Recommendations for improvement</strong> are produced when the platform analyzes the incident and suggests configuration, training, and control changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A deepfake script</b>: deepfakes are offensive media, not post-incident recommendations.</span><span class='qd'><b>A denial-of-service payload</b>: that is an attack, not improvement guidance.</span><span class='qd'><b>A GAN training set</b>: training data for a GAN is unrelated to incident review output.</span>" },
  { id:"D3-025", domain:3, obj:"3.1", diff:"hard", q:"Before AI summarizes controlled data into an incident management platform, what should the organization apply to protect confidentiality of the datasets?", options:["Permanent deletion of the SIEM","Public posting of the raw data","Masking and redaction of controlled data","Disabling all encryption"], answer:2, explain:"<strong>Masking and redaction of controlled data</strong> should be considered before and after processing to protect dataset confidentiality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public posting of the raw data</b>: exposing data violates confidentiality.</span><span class='qd'><b>Permanent deletion of the SIEM</b>: removing the SIEM does not protect data and harms operations.</span><span class='qd'><b>Disabling all encryption</b>: this weakens confidentiality rather than protecting it.</span>" },
  { id:"D3-026", domain:3, obj:"3.1", diff:"medium", q:"A compliance officer insists that AI-authored playbooks and reports be reviewable so the organization can show how the system reached its output. Which principle is being enforced?", options:["Voice cloning","Maximum obfuscation of the output","Zero-shot learning","Auditability for accountability and transparency"], answer:3, explain:"<strong>Auditability for accountability and transparency</strong> requires reviewing AI output to show how the system generated it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Maximum obfuscation of the output</b>: obfuscation hides information, the opposite of auditability.</span><span class='qd'><b>Zero-shot learning</b>: this is a model capability, not a governance principle.</span><span class='qd'><b>Voice cloning</b>: this is an attack technique, unrelated to auditability.</span>" },
  { id:"D3-027", domain:3, obj:"3.1", diff:"easy", q:"A user builds an entire website visually in Wix by dragging objects, and the platform produces the HTML with no code written by the human. What kind of platform is this?", options:["A no-code platform","A SIEM correlation engine","A penetration testing framework","A honeypot"], answer:0, explain:"<strong>A no-code platform</strong> produces code output with no human involvement in writing it, as with Wix building HTML visually.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A SIEM correlation engine</b>: a SIEM analyzes security events, it does not visually build websites.</span><span class='qd'><b>A penetration testing framework</b>: this conducts attacks, not website creation.</span><span class='qd'><b>A honeypot</b>: a honeypot is a decoy, not a development platform.</span>" },
  { id:"D3-028", domain:3, obj:"3.1", diff:"medium", q:"A team customizes a pre-built data dashboard by writing a small amount of their own code while letting an AI platform generate most of the project. Which development approach is this?", options:["No-code","Low-code","Air-gapped","Signature-based"], answer:1, explain:"<strong>Low-code</strong> involves some human-written code while an AI platform accelerates and generates most of the project.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No-code</b>: no-code involves zero human-written code, but here the human writes some.</span><span class='qd'><b>Air-gapped</b>: this describes network isolation, not a development model.</span><span class='qd'><b>Signature-based</b>: this is a detection method, not a coding approach.</span>" },
  { id:"D3-029", domain:3, obj:"3.1", diff:"medium", q:"An organization uses AI to write PowerShell and Python queries against its SIEM and SOAR so that staff unfamiliar with those languages can still produce meaningful reports. What is the primary benefit?", options:["Disabling the SOAR platform","Permanent removal of all analysts","Automatic generation of deepfakes","Faster detection and triage by lowering the scripting skill barrier"], answer:3, explain:"<strong>Faster detection and triage by lowering the scripting skill barrier</strong> describes AI helping non-experts query SIEM and SOAR.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanent removal of all analysts</b>: AI assists analysts, it does not eliminate them.</span><span class='qd'><b>Automatic generation of deepfakes</b>: that is an offensive technique, not query writing.</span><span class='qd'><b>Disabling the SOAR platform</b>: AI queries the SOAR rather than disabling it.</span>" },
  { id:"D3-030", domain:3, obj:"3.1", diff:"hard", q:"An AI summarization tool ingests packet captures, firewall logs, and IDS/IPS logs, then compares them to known threat actor TTPs and provides attribution recommendations with references to ATT&CK and ATLAS. What value does this provide analysts?", options:["Fast, framework-referenced synthesis and attribution of large data sets","A deepfake of an executive","An automated DDoS payload","A GAN for spam generation"], answer:0, explain:"<strong>Fast, framework-referenced synthesis and attribution of large data sets</strong> describes AI summarizing diverse logs and linking to ATT&CK and ATLAS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A deepfake of an executive</b>: that is an attack technique, not log synthesis.</span><span class='qd'><b>An automated DDoS payload</b>: that is offensive, not analytical summarization.</span><span class='qd'><b>A GAN for spam generation</b>: a GAN producing spam is misuse, not defensive attribution.</span>" },
  { id:"D3-031", domain:3, obj:"3.2", diff:"easy", q:"An attacker analyzes millions of samples of a celebrity's voice, mannerisms, and facial structure to generate a convincing fake video endorsing a product. Which AI-enabled attack technique is this?", options:["Code linting","Deepfake creation","Anomaly detection","Regression testing"], answer:1, explain:"<strong>Deepfake creation</strong> uses AI to synthesize realistic video and audio of a real person, as in the Morgan Freeman example.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Code linting</b>: linting reviews code quality and is defensive, not deepfake generation.</span><span class='qd'><b>Anomaly detection</b>: this detects deviations from a baseline, not media synthesis.</span><span class='qd'><b>Regression testing</b>: this validates software changes, not fake media.</span>" },
  { id:"D3-032", domain:3, obj:"3.2", diff:"medium", q:"A threat actor spreads false information through deepfake videos with the specific intent to cause harm and deceive. What is this type of content called?", options:["Misinformation","A signature","Disinformation","A baseline"], answer:2, explain:"<strong>Disinformation</strong> is false information created intentionally to cause harm or deceive, distinct from accidental misinformation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Misinformation</b>: misinformation is false information without the intentional harm element.</span><span class='qd'><b>A signature</b>: a signature is a detection pattern, not deceptive content.</span><span class='qd'><b>A baseline</b>: a baseline is a reference of normal activity, not false content.</span>" },
  { id:"D3-033", domain:3, obj:"3.2", diff:"medium", q:"A user shares false information that they genuinely believe is true, without intent to deceive. According to the source material, this is best categorized as which of the following?", options:["Misinformation","Disinformation","A deepfake payload","A honeypot"], answer:0, explain:"<strong>Misinformation</strong> is false information spread without intent to deceive, contrasted with deliberately harmful disinformation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disinformation</b>: disinformation is intentionally created to cause harm or deceive.</span><span class='qd'><b>A deepfake payload</b>: deepfakes are a media format, not the truthfulness categorization.</span><span class='qd'><b>A honeypot</b>: a honeypot is a defensive decoy, unrelated to false content.</span>" },
  { id:"D3-034", domain:3, obj:"3.2", diff:"hard", q:"An adversary configures two competing neural networks: one generates fake images while the other tries to distinguish them from legitimate content, improving realism over time. Which architecture is this?", options:["An isolation forest","A generative adversarial network (GAN)","A SIEM correlation rule","A software bill of materials"], answer:1, explain:"<strong>A generative adversarial network (GAN)</strong> uses two neural networks working against each other, a generator and a discriminator, to produce realistic content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An isolation forest</b>: this is an anomaly detection algorithm, not a dual-network generator.</span><span class='qd'><b>A SIEM correlation rule</b>: this matches events, it does not generate media.</span><span class='qd'><b>A software bill of materials</b>: an SBOM lists components, not a model architecture.</span>" },
  { id:"D3-035", domain:3, obj:"3.2", diff:"medium", q:"A spammer uses a GAN to slightly alter email content, swap characters, and add spaces into addresses so messages evade normal spam filters. Which attacker goal does this serve?", options:["Improving auditability","Generating an SBOM","Evading signature and pattern-based detection","Enforcing the CIA triad"], answer:2, explain:"<strong>Evading signature and pattern-based detection</strong> is the goal when a GAN subtly mutates spam to bypass filters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improving auditability</b>: evasion reduces transparency, it does not improve auditability.</span><span class='qd'><b>Generating an SBOM</b>: an SBOM is a defensive inventory, unrelated to spam evasion.</span><span class='qd'><b>Enforcing the CIA triad</b>: this is a defensive goal, not the attacker's objective.</span>" },
  { id:"D3-036", domain:3, obj:"3.2", diff:"medium", q:"An attacker uses an LLM to generate many variations of one phishing story template tailored to each victim's job, field, and cultural background. What capability primarily makes the scam more convincing at scale?", options:["Disabling the victim's antivirus","Random uppercase letters only","Manual translation by a single human","Personalized content variation from trained large datasets"], answer:3, explain:"<strong>Personalized content variation from trained large datasets</strong> lets the LLM tailor a story template to each victim at scale.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Random uppercase letters only</b>: random casing does not personalize a scam.</span><span class='qd'><b>Manual translation by a single human</b>: this is slow and not the AI advantage described.</span><span class='qd'><b>Disabling the victim's antivirus</b>: that is a separate action, not what makes the message convincing.</span>" },
  { id:"D3-037", domain:3, obj:"3.2", diff:"hard", q:"An LLM recognizes a new object in input data it has never processed before by comparing its attributes to the existing trained dataset. Which capability is described?", options:["Signature matching","Zero-shot learning","Regression testing","Code linting"], answer:1, explain:"<strong>Zero-shot learning</strong> lets a model recognize new, unseen objects by comparing attributes to its existing training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Signature matching</b>: this requires a known predefined pattern, not recognition of unseen objects.</span><span class='qd'><b>Regression testing</b>: this validates code changes, not model recognition.</span><span class='qd'><b>Code linting</b>: linting checks code quality, unrelated to input recognition.</span>" },
  { id:"D3-038", domain:3, obj:"3.2", diff:"medium", q:"Modern AI-enhanced phishing 3.0 attacks may include a deepfake of a trusted executive the victim has actually met. Why does this defeat a common older detection heuristic?", options:["Because antivirus signatures expand on their own","Because the email server crashes automatically","Because victims can no longer rely on spotting grammar and spelling mistakes","Because the victim's password is reset"], answer:2, explain:"<strong>Because victims can no longer rely on spotting grammar and spelling mistakes</strong>, AI-generated, personalized messages remove the obvious tells.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because the email server crashes automatically</b>: phishing realism does not crash servers.</span><span class='qd'><b>Because antivirus signatures expand on their own</b>: signatures do not self-expand, and this is unrelated.</span><span class='qd'><b>Because the victim's password is reset</b>: phishing seeks credentials, it does not reset passwords automatically.</span>" },
  { id:"D3-039", domain:3, obj:"3.2", diff:"medium", q:"An attacker modifies malware source code so it produces the same outcome but no longer matches existing signatures. Which technique is being used to evade detection?", options:["Human-in-the-loop approval","Composition analysis","Anomaly baselining","Obfuscation and code modification"], answer:3, explain:"<strong>Obfuscation and code modification</strong> changes code so signature and pattern recognition can no longer detect it while behavior stays the same.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Composition analysis</b>: SCA is a defensive review of components, not evasion.</span><span class='qd'><b>Anomaly baselining</b>: this is a defensive detection technique, not malware evasion.</span><span class='qd'><b>Human-in-the-loop approval</b>: this is a governance control, not an attacker technique.</span>" },
  { id:"D3-040", domain:3, obj:"3.2", diff:"medium", q:"A security leader notes that signature-based detection struggles against AI-generated malware. According to the source material, what is the core weakness?", options:["It cannot stay up to date as new attack content is generated faster than signatures can be trained","It uses too much encryption","It requires no maintenance at all","It only works on physical access control"], answer:0, explain:"<strong>It cannot stay up to date as new attack content is generated faster than signatures can be trained</strong> is the noted limitation of signature-based detection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It uses too much encryption</b>: encryption is unrelated to signature freshness.</span><span class='qd'><b>It requires no maintenance at all</b>: the problem is precisely that signatures need constant updates.</span><span class='qd'><b>It only works on physical access control</b>: signature detection applies to malware, not physical access.</span>" },
  { id:"D3-041", domain:3, obj:"3.2", diff:"medium", q:"An adversary embeds an AI tool to crawl the web, compile usernames, phone numbers, and employee images into a target profile much faster than a human could. Which attack phase is being enhanced?", options:["Rollback recovery","Regression testing","Reconnaissance and OSINT collection","SBOM generation"], answer:2, explain:"<strong>Reconnaissance and OSINT collection</strong> is accelerated when AI crawls and summarizes public data into a target profile.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Regression testing</b>: this is a software testing activity, not reconnaissance.</span><span class='qd'><b>Rollback recovery</b>: rollback restores prior code, unrelated to OSINT.</span><span class='qd'><b>SBOM generation</b>: an SBOM inventories components, not OSINT profiles.</span>" },
  { id:"D3-042", domain:3, obj:"3.2", diff:"hard", q:"An AI tool ingests multiple breach dumps, cross-references reused or similar credentials, and suggests likely passwords a victim uses on other platforms. Which capability is this?", options:["M-of-N approval","Deepfake voice cloning","Static application security testing","Automated data correlation across multiple sources"], answer:3, explain:"<strong>Automated data correlation across multiple sources</strong> describes cross-referencing breach dumps to predict reused credentials quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deepfake voice cloning</b>: voice cloning synthesizes audio, not credential correlation.</span><span class='qd'><b>Static application security testing</b>: SAST reviews source code, not breach data.</span><span class='qd'><b>M-of-N approval</b>: that is a defensive governance pattern, not an attack capability.</span>" },
  { id:"D3-043", domain:3, obj:"3.2", diff:"easy", q:"A defender notes that connecting credential dots across many breach dumps would take a human hours or days, but AI does it in moments. What primarily makes these AI-enhanced attacks more dangerous?", options:["The speed and low cost of collecting and interpreting data","The need for specialized physical hardware","The requirement for a court order","The use of only one data source"], answer:0, explain:"<strong>The speed and low cost of collecting and interpreting data</strong>, using public sources and open-source models, makes these attacks more dangerous.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The need for specialized physical hardware</b>: the danger comes from low cost, not specialized hardware.</span><span class='qd'><b>The requirement for a court order</b>: attackers do not need legal authorization.</span><span class='qd'><b>The use of only one data source</b>: the threat is correlation across many sources, not a single one.</span>" },
  { id:"D3-044", domain:3, obj:"3.2", diff:"medium", q:"An attacker uses AI for semantic enrichment, attack prioritization and planning, automated vulnerability validation, and adaptive social engineering. These are listed as key areas where AI aids which activity?", options:["Physical destruction of hardware","Reconnaissance and automated data correlation","Manual paper-based reporting","HVAC temperature regulation"], answer:1, explain:"<strong>Reconnaissance and automated data correlation</strong> is the activity these AI-aided areas support, per the source material.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical destruction of hardware</b>: these are data and planning tasks, not physical destruction.</span><span class='qd'><b>Manual paper-based reporting</b>: AI automates correlation, the opposite of manual reporting.</span><span class='qd'><b>HVAC temperature regulation</b>: this is unrelated building automation.</span>" },
  { id:"D3-045", domain:3, obj:"3.2", diff:"hard", q:"An adversary uses AI to compare a honeypot's response times and offered services to those of real systems, then quickly pivots away from the decoy. How does AI benefit the attacker here?", options:["By performing regression testing","By generating a Software Bill of Materials","By enforcing M-of-N approvals","By optimizing honeypot detection to avoid wasting time on decoys"], answer:3, explain:"<strong>By optimizing honeypot detection to avoid wasting time on decoys</strong>, AI spots inconsistencies so the attacker pivots to real targets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>By generating a Software Bill of Materials</b>: an SBOM is a defensive inventory, not honeypot detection.</span><span class='qd'><b>By enforcing M-of-N approvals</b>: that is a defensive approval pattern.</span><span class='qd'><b>By performing regression testing</b>: regression testing is software validation, not honeypot evasion.</span>" },
  { id:"D3-046", domain:3, obj:"3.2", diff:"medium", q:"A defender uses AI to adapt a honeypot in real time, manipulate data shown to attackers, and make it harder to identify as a decoy. What is the strategic benefit?", options:["Keeping attackers occupied while detection and response work to isolate the threat","Permanently deleting all firewall rules","Generating phishing emails for the attacker","Cloning the CEO's voice"], answer:0, explain:"<strong>Keeping attackers occupied while detection and response work to isolate the threat</strong> is the defensive benefit of an AI-adaptive honeypot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanently deleting all firewall rules</b>: this would weaken defenses, not aid them.</span><span class='qd'><b>Generating phishing emails for the attacker</b>: that helps attackers, not defenders.</span><span class='qd'><b>Cloning the CEO's voice</b>: voice cloning is an offensive technique.</span>" },
  { id:"D3-047", domain:3, obj:"3.2", diff:"medium", q:"During an AI-automated DDoS, the system continuously probes firewalls and signature-based detection, observes responses, and updates the attack profile to minimize detection. Which AI advantage is central?", options:["Slower-than-human packet generation","Real-time analysis of defenses to adapt the attack profile","Reliance on a single static payload","Mandatory human approval for each packet"], answer:1, explain:"<strong>Real-time analysis of defenses to adapt the attack profile</strong> lets AI probe controls and continuously update the most impactful attack.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slower-than-human packet generation</b>: AI generates data streams faster than humans, not slower.</span><span class='qd'><b>Reliance on a single static payload</b>: the attack adapts, it is not static.</span><span class='qd'><b>Mandatory human approval for each packet</b>: automation removes per-packet human approval.</span>" },
  { id:"D3-048", domain:3, obj:"3.2", diff:"easy", q:"An attacker uses AI to automatically generate fake login webpages for credential harvesting and tailor social engineering lures. Which phase of the attack does this support?", options:["Regression testing","Software bill of materials auditing","Payload creation and delivery","Honeypot deployment by the defender"], answer:2, explain:"<strong>Payload creation and delivery</strong> is supported when AI builds fake pages and crafts social engineering to deliver attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Software bill of materials auditing</b>: an SBOM audit is a defensive activity.</span><span class='qd'><b>Regression testing</b>: this validates software, not phishing payloads.</span><span class='qd'><b>Honeypot deployment by the defender</b>: deploying decoys is defensive, not the attacker's payload work.</span>" },
  { id:"D3-049", domain:3, obj:"3.2", diff:"hard", q:"AI creates malware that adapts to an organization's defensive behaviors through advanced obfuscation and code modification. Which defensive control is most directly undermined?", options:["Signature-based antivirus and antimalware detection","Physical fencing","Cable management","Office lighting controls"], answer:0, explain:"<strong>Signature-based antivirus and antimalware detection</strong> is undermined because obfuscation prevents readily available signature tools from matching the code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical fencing</b>: a fence is a physical control, irrelevant to malware obfuscation.</span><span class='qd'><b>Cable management</b>: this is an operational hygiene practice, not a detection control.</span><span class='qd'><b>Office lighting controls</b>: lighting has no bearing on malware detection.</span>" },
  { id:"D3-050", domain:3, obj:"3.2", diff:"medium", q:"A security team is told that obfuscation can hide information in plain sight using alternative language or code words within content. What is the primary impact on defenders?", options:["Encryption keys rotate automatically","Content becomes harder to process and signatures may miss it","All alerts are suppressed by the firewall","The SIEM gains perfect accuracy"], answer:1, explain:"<strong>Content becomes harder to process and signatures may miss it</strong> because obfuscation disguises the malicious content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption keys rotate automatically</b>: obfuscation of content does not rotate keys.</span><span class='qd'><b>All alerts are suppressed by the firewall</b>: obfuscation evades detection, it does not control the firewall.</span><span class='qd'><b>The SIEM gains perfect accuracy</b>: obfuscation reduces detection accuracy, not improves it.</span>" },
  { id:"D3-051", domain:3, obj:"3.2", diff:"medium", q:"An analyst learns that adversarial networks can confuse or mislead learning models, causing incorrect predictions and outcomes. Which example does the source material give of such a network?", options:["A content delivery network (CDN)","A virtual private network (VPN)","A generative adversarial network (GAN)","A storage area network (SAN)"], answer:2, explain:"<strong>A generative adversarial network (GAN)</strong> is the example given of an adversarial network that can mislead learning models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A virtual private network (VPN)</b>: a VPN encrypts traffic and is not an adversarial model.</span><span class='qd'><b>A content delivery network (CDN)</b>: a CDN distributes content, not adversarial generation.</span><span class='qd'><b>A storage area network (SAN)</b>: a SAN is storage infrastructure, unrelated to ML adversarial attacks.</span>" },
  { id:"D3-052", domain:3, obj:"3.2", diff:"hard", q:"A risk officer summarizes the dangers of malicious AI content: loss of public and corporate trust, security risks from bypassing controls, and ethical concerns over manipulating decisions in finance and legal systems. Which best captures the overall concern?", options:["Improved spam filter accuracy","Reduced electricity costs","Faster manual code review","Erosion of trust plus security and ethical risks from manipulated content"], answer:3, explain:"<strong>Erosion of trust plus security and ethical risks from manipulated content</strong> captures the combined dangers described.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reduced electricity costs</b>: cost savings are not the concern raised.</span><span class='qd'><b>Faster manual code review</b>: this is a benefit, not the risk described.</span><span class='qd'><b>Improved spam filter accuracy</b>: malicious AI content degrades, not improves, filter accuracy.</span>" },
  { id:"D3-053", domain:3, obj:"3.2", diff:"medium", q:"An attacker ingests a target's interviews and Instagram posts to capture facial muscle movement, voice tone, and inflection for a synthetic clone. Which AI capability makes this possible?", options:["Static code linting","High-functioning synthesis of imagery and audio including voice cloning","Anomaly baselining","M-of-N voting"], answer:1, explain:"<strong>High-functioning synthesis of imagery and audio including voice cloning</strong> lets AI capture mannerisms and produce realistic deepfakes from public content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static code linting</b>: linting reviews code, not media synthesis.</span><span class='qd'><b>Anomaly baselining</b>: this is defensive detection, not content generation.</span><span class='qd'><b>M-of-N voting</b>: that is a defensive approval pattern.</span>" },
  { id:"D3-054", domain:3, obj:"3.2", diff:"medium", q:"AI deepfake content is fed back into Facebook and Instagram for global dissemination or used in elaborate social engineering. Which broader societal risk does the source material warn about?", options:["Automatic encryption of social media","Permanent improvement of journalism","Eventual public distrust of legitimate content","Elimination of all phishing"], answer:2, explain:"<strong>Eventual public distrust of legitimate content</strong> is the warned societal consequence of widespread deepfakes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanent improvement of journalism</b>: deepfakes degrade trust rather than improve journalism.</span><span class='qd'><b>Automatic encryption of social media</b>: dissemination of deepfakes does not encrypt platforms.</span><span class='qd'><b>Elimination of all phishing</b>: deepfakes enhance phishing, they do not eliminate it.</span>" },
  { id:"D3-055", domain:3, obj:"3.2", diff:"easy", q:"An attacker pretends to be a company's CEO to trick an employee into a fraudulent wire transfer. The act of representing or pretending to be a person or company for fraud is called what?", options:["Rollback","Linting","Baselining","Impersonation"], answer:3, explain:"<strong>Impersonation</strong> is representing or pretending to be a person or company for the purpose of fraud.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Linting</b>: linting reviews code quality, not identity fraud.</span><span class='qd'><b>Baselining</b>: baselining establishes normal activity, not impersonation.</span><span class='qd'><b>Rollback</b>: rollback restores prior code, unrelated to fraud.</span>" },
  { id:"D3-056", domain:3, obj:"3.2", diff:"hard", q:"A blackmail and influence campaign is enhanced by AI that fabricates realistic videos of events that never happened. Which combination of risks does this most directly create?", options:["Fraudulent targeting of individuals and organizations plus enhanced influence operations","Reduced cloud spending","Stronger encryption by default","Automatic SBOM creation"], answer:0, explain:"<strong>Fraudulent targeting of individuals and organizations plus enhanced influence operations</strong> describes how AI-generated fake events enable blackmail and influence campaigns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reduced cloud spending</b>: this is a cost matter, unrelated to influence operations.</span><span class='qd'><b>Stronger encryption by default</b>: fabricated video does not strengthen encryption.</span><span class='qd'><b>Automatic SBOM creation</b>: an SBOM is a defensive inventory, irrelevant here.</span>" },
  { id:"D3-057", domain:3, obj:"3.2", diff:"medium", q:"Whether through human-in-the-loop operations or full automation, both attackers and defenders can use AI to do what to cyber attacks, according to the source?", options:["Eliminate the need for any data","Make them slower and less accurate","Scale them with greater accuracy and sophistication","Confine them to a single host only"], answer:2, explain:"<strong>Scale them with greater accuracy and sophistication</strong> is how AI affects cyber attacks for both sides.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Make them slower and less accurate</b>: AI increases speed and accuracy, not the reverse.</span><span class='qd'><b>Eliminate the need for any data</b>: AI attacks rely heavily on data correlation.</span><span class='qd'><b>Confine them to a single host only</b>: AI enables large-scale, adaptive attacks.</span>" },
  { id:"D3-058", domain:3, obj:"3.2", diff:"medium", q:"An attacker uses AI to convert manual processes of target selection, payload crafting, and lure delivery into automated steps, even modifying the attack mid-operation when defenders react. Which is the primary AI advantage?", options:["Slower payload delivery","Guaranteed legal compliance","Reduced need for reconnaissance","Enhanced speed of generating and changing attacks on the fly"], answer:3, explain:"<strong>Enhanced speed of generating and changing attacks on the fly</strong> is the central advantage AI gives automated attacks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteed legal compliance</b>: attackers are not pursuing compliance.</span><span class='qd'><b>Reduced need for reconnaissance</b>: AI enhances reconnaissance rather than removing it.</span><span class='qd'><b>Slower payload delivery</b>: AI speeds up delivery, not slows it.</span>" },
  { id:"D3-059", domain:3, obj:"3.2", diff:"medium", q:"Security experts are concerned that AI use in both authorized penetration testing and malicious attacks is growing exponentially. What core dual-use property drives this concern?", options:["The same AI techniques benefit both attackers and defenders","AI only ever helps defenders","AI only ever helps attackers","AI cannot be used in testing"], answer:0, explain:"<strong>The same AI techniques benefit both attackers and defenders</strong> is the dual-use concern raised about AI growth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI only ever helps defenders</b>: the source explicitly notes malicious use too.</span><span class='qd'><b>AI only ever helps attackers</b>: AI also aids authorized testing and defense.</span><span class='qd'><b>AI cannot be used in testing</b>: AI is explicitly used in penetration testing.</span>" },
  { id:"D3-060", domain:3, obj:"3.2", diff:"hard", q:"An AI-automated attack continuously monitors how a victim responds and identifies the most impactful attack profile to cause maximum damage. Which capability best summarizes this behavior?", options:["One-time static payload deployment","Continuous response analysis to maximize attack impact","Defensive M-of-N approval","Composition analysis of SBOMs"], answer:1, explain:"<strong>Continuous response analysis to maximize attack impact</strong> describes the AI monitoring responses and tuning the attack for greatest damage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>One-time static payload deployment</b>: the attack adapts continuously, not once.</span><span class='qd'><b>Defensive M-of-N approval</b>: that is a defensive governance pattern.</span><span class='qd'><b>Composition analysis of SBOMs</b>: SCA is a defensive code review, not an offensive tactic.</span>" },
  { id:"D3-061", domain:3, obj:"3.3", diff:"easy", q:"A team uses Splunk SOAR playbooks to automatically perform routine triage tasks normally done by humans when a security incident occurs. What is the primary benefit of this automation?", options:["Disabling endpoint monitoring","Permanent removal of all logging","Generation of deepfake audio","Faster, more consistent incident triage with less human effort"], answer:3, explain:"<strong>Faster, more consistent incident triage with less human effort</strong> is the benefit of SOAR playbooks automating typical analyst tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanent removal of all logging</b>: automation relies on logs, it does not remove them.</span><span class='qd'><b>Generation of deepfake audio</b>: that is an offensive technique, not triage automation.</span><span class='qd'><b>Disabling endpoint monitoring</b>: SOAR depends on monitoring data, not disabling it.</span>" },
  { id:"D3-062", domain:3, obj:"3.3", diff:"medium", q:"An engineer uses scripts of code to automate the deployment, configuration, and management of firewalls and servers, including AI supporting infrastructure. Which practice is this?", options:["Infrastructure as Code (IaC)","Voice cloning","Signature matching","Deepfake synthesis"], answer:0, explain:"<strong>Infrastructure as Code (IaC)</strong> uses scripts to automate deployment, configuration, and management of systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Voice cloning</b>: voice cloning is an attack technique, not infrastructure automation.</span><span class='qd'><b>Signature matching</b>: this is a detection method, not deployment automation.</span><span class='qd'><b>Deepfake synthesis</b>: deepfakes generate fake media, unrelated to IaC.</span>" },
  { id:"D3-063", domain:3, obj:"3.3", diff:"medium", q:"A SIEM receives firewall and endpoint alerts indicating a likely DoS against the public website. An AI monitoring solution begins log collection, opens a ticket, notifies staff, and can block traffic by source IP while documenting each change. Which workflow concept is illustrated?", options:["Manual paper-based reporting","AI-driven automated incident response","Deepfake generation","Honeypot fingerprinting by attackers"], answer:1, explain:"<strong>AI-driven automated incident response</strong> describes AI collecting evidence, ticketing, notifying, and remediating while documenting changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual paper-based reporting</b>: the workflow is automated, not manual paper.</span><span class='qd'><b>Deepfake generation</b>: that is an offensive technique, not incident response.</span><span class='qd'><b>Honeypot fingerprinting by attackers</b>: that is an attacker activity, not defensive automation.</span>" },
  { id:"D3-064", domain:3, obj:"3.3", diff:"hard", q:"How does the AI incident-response system in the source material know what an attack is and how to respond appropriately?", options:["By copying the attacker's playbook directly","Through random guessing each time","Through training on attack profiles, TTPs, and expected responses based on best practices and policy","By disabling all detection rules"], answer:2, explain:"<strong>Through training on attack profiles, TTPs, and expected responses based on best practices and policy</strong> is how engineers prepare the model to respond correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Through random guessing each time</b>: trained models do not guess randomly.</span><span class='qd'><b>By copying the attacker's playbook directly</b>: defenders train on TTPs and responses, not attacker playbooks verbatim.</span><span class='qd'><b>By disabling all detection rules</b>: disabling detection would prevent response, not enable it.</span>" },
  { id:"D3-065", domain:3, obj:"3.3", diff:"medium", q:"A concern with AI automated response is that the system might make changes when no incident is occurring. What safeguard does the source material emphasize?", options:["Ensuring the AI only takes prescribed action when truly needed","Letting the AI change anything without limits","Removing all approval gates","Disabling identification of legitimate traffic"], answer:0, explain:"<strong>Ensuring the AI only takes prescribed action when truly needed</strong> guards against unnecessary or harmful automated changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Letting the AI change anything without limits</b>: unbounded action is the exact risk to avoid.</span><span class='qd'><b>Removing all approval gates</b>: approvals help control critical changes.</span><span class='qd'><b>Disabling identification of legitimate traffic</b>: distinguishing legitimate traffic is needed to avoid false action.</span>" },
  { id:"D3-066", domain:3, obj:"3.3", diff:"medium", q:"An AI response system has predetermined approval to make minor changes automatically, but critical changes require a person to review and approve. Which control model is this?", options:["Fully autonomous with no oversight","Human-in-the-loop approval for high-impact changes","No automation at all","Signature-only detection"], answer:1, explain:"<strong>Human-in-the-loop approval for high-impact changes</strong> lets AI handle routine actions while requiring human sign-off on critical ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Fully autonomous with no oversight</b>: critical changes still require human approval here.</span><span class='qd'><b>No automation at all</b>: the system does automate minor changes.</span><span class='qd'><b>Signature-only detection</b>: this is a detection method, not an approval model.</span>" },
  { id:"D3-067", domain:3, obj:"3.3", diff:"medium", q:"A cloud platform auto-scales web servers to handle a product launch, but when it reaches its programmed peak limit it only alerts technicians for manual approval to exceed it. Which design principle does this reflect?", options:["No scaling ever permitted","Unlimited automatic scaling regardless of cost","Automated action within bounds, escalating to humans at hard limits","Mandatory deepfake review"], answer:2, explain:"<strong>Automated action within bounds, escalating to humans at hard limits</strong> describes auto-scaling that defers to humans when exceeding programmed limits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unlimited automatic scaling regardless of cost</b>: the system stops at its peak limit and escalates.</span><span class='qd'><b>No scaling ever permitted</b>: the system does scale automatically up to a limit.</span><span class='qd'><b>Mandatory deepfake review</b>: deepfakes are unrelated to cloud auto-scaling.</span>" },
  { id:"D3-068", domain:3, obj:"3.3", diff:"easy", q:"A DevSecOps team integrates automated security checks, compliance, and continuous monitoring into the CI/CD pipeline without slowing delivery. What does DevSecOps integrate into DevOps workflows?", options:["Voice cloning","Deepfake generation","Physical access controls","Security practices"], answer:3, explain:"<strong>Security practices</strong> are integrated into DevOps workflows by DevSecOps, emphasizing automated checks and continuous monitoring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deepfake generation</b>: that is an attack technique, not a DevSecOps practice.</span><span class='qd'><b>Physical access controls</b>: DevSecOps focuses on the software lifecycle, not physical gates.</span><span class='qd'><b>Voice cloning</b>: voice cloning is offensive media synthesis, unrelated to CI/CD security.</span>" },
  { id:"D3-069", domain:3, obj:"3.3", diff:"medium", q:"A team uses AI to review third-party libraries and dependencies in their project and analyze the SBOM for vulnerabilities. Which deeper-level inspection is described?", options:["Voice cloning","Software composition analysis (SCA)","Deepfake detection","Honeypot fingerprinting"], answer:1, explain:"<strong>Software composition analysis (SCA)</strong> reviews third-party components and dependencies, including SBOM analysis, for vulnerabilities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Voice cloning</b>: this is an attack technique, not dependency analysis.</span><span class='qd'><b>Deepfake detection</b>: this concerns synthetic media, not software components.</span><span class='qd'><b>Honeypot fingerprinting</b>: that is an attacker reconnaissance activity.</span>" },
  { id:"D3-070", domain:3, obj:"3.3", diff:"medium", q:"A compliance lead requests a detailed list of all libraries, frameworks, dependencies, datasets, and models that make up an AI application. Which artifact provides this?", options:["A GAN discriminator","A deepfake script","A Software Bill of Materials (SBOM)","A phishing template"], answer:2, explain:"<strong>A Software Bill of Materials (SBOM)</strong> provides a detailed list of all libraries, frameworks, dependencies, datasets, and models.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A deepfake script</b>: a deepfake script generates fake media, not a component inventory.</span><span class='qd'><b>A GAN discriminator</b>: this is part of a model architecture, not a component list.</span><span class='qd'><b>A phishing template</b>: a phishing template is an attack artifact.</span>" },
  { id:"D3-071", domain:3, obj:"3.3", diff:"medium", q:"An AI-assisted process tests individual functions, methods, and classes within code to ensure each works as intended, like testing a house's foundation before the frame. Which test type is this?", options:["Honeypot testing","Penetration testing","Deepfake testing","Unit testing"], answer:3, explain:"<strong>Unit testing</strong> analyzes individual functions, methods, and classes to ensure they work as intended.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Penetration testing</b>: this actively attacks a system rather than testing isolated units.</span><span class='qd'><b>Deepfake testing</b>: this is not a standard test type and relates to fake media.</span><span class='qd'><b>Honeypot testing</b>: this concerns decoy systems, not code units.</span>" },
  { id:"D3-072", domain:3, obj:"3.3", diff:"hard", q:"An AI verifies that the most appropriate model is used for a task, that inputs are handled correctly, and runs fairness and data-leak checks plus penetration testing against an injection vulnerability. Which testing type is described?", options:["Model testing","Unit testing","Linting","Signature matching"], answer:0, explain:"<strong>Model testing</strong> ensures the right model is used, inputs are handled correctly, and includes fairness, data-leak, and penetration checks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Unit testing</b>: unit testing targets individual code functions, not model appropriateness and fairness.</span><span class='qd'><b>Linting</b>: linting checks code style, not model behavior.</span><span class='qd'><b>Signature matching</b>: this is a detection method, not model validation.</span>" },
  { id:"D3-073", domain:3, obj:"3.3", diff:"medium", q:"After each code update, engineers run repeated tests, including feeding random inputs through fuzzing, to ensure changes do not break existing functionality. Which test type is this?", options:["Anomaly detection","Composition analysis","Regression testing","Voice cloning"], answer:2, explain:"<strong>Regression testing</strong> runs repeated tests after each modification, including fuzzing, to catch unexpected breakage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Composition analysis</b>: SCA reviews third-party components, not change-driven regressions.</span><span class='qd'><b>Anomaly detection</b>: this finds deviations in operational data, not code regressions.</span><span class='qd'><b>Voice cloning</b>: this is an attack technique, unrelated to testing.</span>" },
  { id:"D3-074", domain:3, obj:"3.3", diff:"medium", q:"Regression testing reveals that a minor code change broke the application. The team restores the previously working code while researching a fix. What is this action called?", options:["A baseline reset","A deepfake","A honeypot","A rollback"], answer:3, explain:"<strong>A rollback</strong> restores previously working code for use while another solution is researched.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A deepfake</b>: a deepfake is synthetic media, unrelated to code restoration.</span><span class='qd'><b>A honeypot</b>: a honeypot is a decoy system, not a code restore.</span><span class='qd'><b>A baseline reset</b>: this is not the term used for restoring prior code.</span>" },
  { id:"D3-075", domain:3, obj:"3.3", diff:"hard", q:"A team wants to avoid letting a single AI model approve all changes, fearing hallucination and single points of failure. They require 7 of 10 models to agree before approving a change. Which design pattern is this?", options:["M-of-N approval","Zero-shot learning","Signature matching","Infrastructure as Code"], answer:0, explain:"<strong>M-of-N approval</strong> requires feedback from multiple models or agents, here 7 of 10, before an approval is granted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Zero-shot learning</b>: this is a recognition capability, not a multi-model approval pattern.</span><span class='qd'><b>Signature matching</b>: this is a detection method, not a consensus mechanism.</span><span class='qd'><b>Infrastructure as Code</b>: IaC automates deployment, not approval voting.</span>" },
  { id:"D3-076", domain:3, obj:"3.3", diff:"medium", q:"In an M-of-N approval scheme where 7 of 10 models must approve, only 3 models approve a proposed change. What happens?", options:["The change is automatically deployed","The change is not approved","All 10 models are deleted","The SBOM is regenerated"], answer:1, explain:"<strong>The change is not approved</strong> because fewer than the required M models endorsed it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The change is automatically deployed</b>: deployment requires meeting the threshold, which was not met.</span><span class='qd'><b>All 10 models are deleted</b>: failing a vote does not delete the models.</span><span class='qd'><b>The SBOM is regenerated</b>: an approval vote does not trigger SBOM regeneration.</span>" },
  { id:"D3-077", domain:3, obj:"3.3", diff:"hard", q:"Beyond reducing single points of failure, what additional benefit does the M-of-N pattern provide according to the source material?", options:["It encrypts all network traffic","It guarantees the cheapest possible model is used","It removes the need for any human oversight","It helps ensure models are not hallucinating and that safety checks are not bypassed"], answer:3, explain:"<strong>It helps ensure models are not hallucinating and that safety checks are not bypassed</strong> by requiring multi-model consensus.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees the cheapest possible model is used</b>: M-of-N is about consensus, not cost.</span><span class='qd'><b>It removes the need for any human oversight</b>: humans remain accountable and in the loop.</span><span class='qd'><b>It encrypts all network traffic</b>: M-of-N is an approval pattern, not an encryption control.</span>" },
  { id:"D3-078", domain:3, obj:"3.3", diff:"medium", q:"The source material stresses that automated change approvals in DevSecOps must be clearly logged and verified by humans because AI systems cannot be held accountable. Which principle does this reflect?", options:["Human accountability and compliance verification","Full autonomy without records","Elimination of all logging","Maximum obfuscation"], answer:0, explain:"<strong>Human accountability and compliance verification</strong> is required since AI cannot be held accountable for its actions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full autonomy without records</b>: changes must be logged and verified, not unrecorded.</span><span class='qd'><b>Elimination of all logging</b>: logging is required for compliance.</span><span class='qd'><b>Maximum obfuscation</b>: obfuscation hides activity, opposing accountability.</span>" },
  { id:"D3-079", domain:3, obj:"3.3", diff:"medium", q:"A DevSecOps team deploys AI agents to perform automated threat detection, policy enforcement, and predictive analysis in response to events. Which overall benefit does the source attribute to AI here?", options:["Guaranteed elimination of all vulnerabilities","Increased efficiency, fewer human errors, and proactive issue identification","Removal of the need for any testing","Slower decision-making"], answer:1, explain:"<strong>Increased efficiency, fewer human errors, and proactive issue identification</strong> are the benefits AI brings to DevSecOps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteed elimination of all vulnerabilities</b>: AI reduces but cannot guarantee zero vulnerabilities.</span><span class='qd'><b>Removal of the need for any testing</b>: testing remains essential in DevSecOps.</span><span class='qd'><b>Slower decision-making</b>: AI speeds up decisions, not slows them.</span>" },
  { id:"D3-080", domain:3, obj:"3.3", diff:"medium", q:"An organization implements security as code to enhance SAST and DAST tools and to add anomaly detection within communications and user-interaction behaviors. Which capability does the behavior-based piece represent?", options:["Deepfake synthesis","Voice cloning","Behavior analytics","Signature authoring"], answer:2, explain:"<strong>Behavior analytics</strong> describes anomaly detection within communications and user-interaction behaviors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Voice cloning</b>: this is an attack technique, not behavior analytics.</span><span class='qd'><b>Deepfake synthesis</b>: deepfakes generate media, not analyze behavior.</span><span class='qd'><b>Signature authoring</b>: writing signatures is pattern-based, not behavior analytics.</span>" },
  { id:"D3-081", domain:3, obj:"3.3", diff:"easy", q:"For SOC-specific tasking, the source lists threat detection, alert triage, and gathering threat intelligence for incident analysis and reporting. Which broad goal does AI serve in the SOC?", options:["Automating and accelerating core SOC functions","Generating disinformation campaigns","Replacing all encryption","Building physical fences"], answer:0, explain:"<strong>Automating and accelerating core SOC functions</strong> like detection, triage, and threat intel is AI's SOC role.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generating disinformation campaigns</b>: that is an attacker misuse, not a SOC function.</span><span class='qd'><b>Replacing all encryption</b>: AI in the SOC does not replace cryptographic controls.</span><span class='qd'><b>Building physical fences</b>: physical barriers are unrelated to SOC AI tasks.</span>" },
  { id:"D3-082", domain:3, obj:"3.3", diff:"medium", q:"A team uses AI to monitor for utilization issues and detect performance anomalies, identifying areas for improvement in both infrastructure and the application. What capability is this?", options:["Deepfake creation","Anomaly detection of performance","Honeypot fingerprinting","Phishing template generation"], answer:1, explain:"<strong>Anomaly detection of performance</strong> monitors utilization and flags performance deviations for improvement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deepfake creation</b>: deepfakes are offensive media, not performance monitoring.</span><span class='qd'><b>Honeypot fingerprinting</b>: that is an attacker reconnaissance activity.</span><span class='qd'><b>Phishing template generation</b>: phishing templates are attack artifacts.</span>" },
  { id:"D3-083", domain:3, obj:"3.3", diff:"hard", q:"An AI pipeline runs SAST on source code and DAST on the running application as part of continuous security. What is the key difference between SAST and DAST in this context?", options:["DAST only checks code style","SAST and DAST are identical","SAST analyzes source code statically while DAST tests the running application dynamically","SAST only clones voices"], answer:2, explain:"<strong>SAST analyzes source code statically while DAST tests the running application dynamically</strong> is the core distinction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SAST and DAST are identical</b>: they differ in static versus dynamic analysis.</span><span class='qd'><b>DAST only checks code style</b>: DAST tests a running app for security flaws, not style.</span><span class='qd'><b>SAST only clones voices</b>: SAST analyzes code, not media.</span>" },
  { id:"D3-084", domain:3, obj:"3.3", diff:"medium", q:"A security analyst feeds packet captures, firewall logs, and antivirus monitoring data into an AI tool to produce a concise, accurate summary report quickly. Which AI use case is this?", options:["Manual line-by-line log reading","Generative adversarial spam","Deepfake voice cloning","AI content summarization of large security data sets"], answer:3, explain:"<strong>AI content summarization of large security data sets</strong> describes ingesting diverse logs and producing accurate summaries quickly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generative adversarial spam</b>: that is an attack output, not defensive summarization.</span><span class='qd'><b>Deepfake voice cloning</b>: voice cloning is offensive media, not log summarization.</span><span class='qd'><b>Manual line-by-line log reading</b>: AI summarization replaces this slow manual effort.</span>" },
  { id:"D3-085", domain:3, obj:"3.3", diff:"medium", q:"A SOC wants AI to generate code for routine processes so analysts can quickly produce reports and summaries from SIEM and SOAR data. What is this use case called?", options:["Deepfake creation","AI-powered security scripting","Honeypot deployment","Disinformation seeding"], answer:1, explain:"<strong>AI-powered security scripting</strong> generates code for routine processes and queries against SIEM and SOAR.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deepfake creation</b>: that is an offensive technique, not scripting.</span><span class='qd'><b>Honeypot deployment</b>: deploying decoys is a detection tactic, not scripting.</span><span class='qd'><b>Disinformation seeding</b>: that is an attacker activity.</span>" },
  { id:"D3-086", domain:3, obj:"3.3", diff:"medium", q:"During incident handling, an AI workflow collects, processes, and acts on data points to maintain confidentiality, integrity, and accountability during a business process. Which model is being upheld?", options:["The OSI model","The GAN architecture","The CIA triad","The STRIDE-only model"], answer:2, explain:"<strong>The CIA triad</strong> of confidentiality, integrity, and accountability is maintained by the AI-supplemented security workflow.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The GAN architecture</b>: a GAN is a generative model, not a security objective model.</span><span class='qd'><b>The OSI model</b>: the OSI model describes networking layers, not security objectives.</span><span class='qd'><b>The STRIDE-only model</b>: STRIDE is a threat-modeling framework, not the triad described.</span>" },
  { id:"D3-087", domain:3, obj:"3.3", diff:"hard", q:"An AI incident-response system implements changes while responding to an attack and automatically documents each change, attaching the record to the support ticket. Why is this documentation important?", options:["It deletes the incident ticket","It makes the attack succeed faster","It hides the changes from auditors","It provides an auditable record of automated actions for accountability"], answer:3, explain:"<strong>It provides an auditable record of automated actions for accountability</strong>, attaching change documentation to the ticket.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the attack succeed faster</b>: documentation aids defenders, not attackers.</span><span class='qd'><b>It hides the changes from auditors</b>: the goal is transparency, not concealment.</span><span class='qd'><b>It deletes the incident ticket</b>: the record is attached to the ticket, not deleted.</span>" },
  { id:"D3-088", domain:3, obj:"3.3", diff:"medium", q:"A no-code platform produces working code with zero human code writing, letting a user design a program 100% visually. Which scenario fits no-code best?", options:["Building a website by dragging objects while the platform generates the HTML","Hand-writing assembly for a device driver","Manually authoring antivirus signatures","Reverse engineering malware byte by byte"], answer:0, explain:"<strong>Building a website by dragging objects while the platform generates the HTML</strong> exemplifies no-code development.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hand-writing assembly for a device driver</b>: this is deeply manual coding, the opposite of no-code.</span><span class='qd'><b>Manually authoring antivirus signatures</b>: this is manual analyst work, not no-code generation.</span><span class='qd'><b>Reverse engineering malware byte by byte</b>: this is intensive manual analysis, not no-code.</span>" },
  { id:"D3-089", domain:3, obj:"3.3", diff:"easy", q:"A team defines CI/CD as practices that automate software development, testing, and deployment. According to the source, where should compliance checks be placed?", options:["Never, to keep delivery fast","Only after deployment to production","Throughout the CI/CD process","Only in the deepfake module"], answer:2, explain:"<strong>Throughout the CI/CD process</strong> checks should be placed to ensure compliance with regulatory requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only after deployment to production</b>: checks belong throughout the pipeline, not just at the end.</span><span class='qd'><b>Never, to keep delivery fast</b>: DevSecOps integrates checks without sacrificing speed.</span><span class='qd'><b>Only in the deepfake module</b>: deepfakes are not part of CI/CD compliance.</span>" },
  { id:"D3-090", domain:3, obj:"3.3", diff:"medium", q:"Engineers worry that one minor code change could snowball and break the entire application. Which automated testing approach is designed to catch this immediately so the change can be rolled back if needed?", options:["Deepfake synthesis","Voice cloning","Signature matching","Regression testing"], answer:3, explain:"<strong>Regression testing</strong> runs after each change to catch snowball failures so a rollback can occur if necessary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Voice cloning</b>: this is an attack technique, not change validation.</span><span class='qd'><b>Signature matching</b>: this is a detection method, not regression validation.</span><span class='qd'><b>Deepfake synthesis</b>: this generates media, unrelated to code testing.</span>" },
  { id:"D3-091", domain:3, obj:"3.3", diff:"medium", q:"If regression testing shows no complications from a code modification, what does the source material say may happen next?", options:["The change may be automatically deployed across the entire software platform","The change must always be discarded","The whole pipeline must be deleted","The model must be retrained from scratch"], answer:0, explain:"<strong>The change may be automatically deployed across the entire software platform</strong> when regression testing finds no issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The change must always be discarded</b>: passing tests means the change can proceed, not be discarded.</span><span class='qd'><b>The whole pipeline must be deleted</b>: a clean test does not require deleting the pipeline.</span><span class='qd'><b>The model must be retrained from scratch</b>: code regression success does not mandate retraining.</span>" },
  { id:"D3-092", domain:3, obj:"3.3", diff:"hard", q:"A SOC uses an AI assistant to initiate a playbook and push case management updates to the entire team after a SIEM alert. Which benefit does this personal-assistant automation provide?", options:["Generation of deepfake endorsements","Coordinated response and team-wide situational awareness","Automatic credential harvesting","Disabling the incident management platform"], answer:1, explain:"<strong>Coordinated response and team-wide situational awareness</strong> result from the assistant initiating playbooks and updating the team.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Generation of deepfake endorsements</b>: that is an offensive misuse, not coordination.</span><span class='qd'><b>Automatic credential harvesting</b>: harvesting credentials is an attack, not defensive coordination.</span><span class='qd'><b>Disabling the incident management platform</b>: the assistant updates the platform rather than disabling it.</span>" },
  { id:"D3-093", domain:3, obj:"3.3", diff:"medium", q:"An AI-assisted DevSecOps process performs automated code analysis, bug detection, and vulnerability scanning continuously during development. What primary advantage does integrating these into the pipeline provide?", options:["Automatic generation of phishing lures","Slower releases with more manual steps","Guaranteed removal of human accountability","Proactive identification and correction of issues before release"], answer:3, explain:"<strong>Proactive identification and correction of issues before release</strong> is the advantage of continuous AI-assisted checks in the pipeline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slower releases with more manual steps</b>: automation speeds releases and reduces manual effort.</span><span class='qd'><b>Guaranteed removal of human accountability</b>: humans remain accountable for changes.</span><span class='qd'><b>Automatic generation of phishing lures</b>: that is an attacker activity, not DevSecOps benefit.</span>" },
  { id:"D3-094", domain:3, obj:"3.3", diff:"medium", q:"An analyst asks an AI system like ChatGPT to produce fully functioning code in multiple languages with little to no human involvement in writing it. Which shift in software development does this represent?", options:["AI-driven automated code generation","Manual machine-language programming","Physical penetration testing","Honeypot fingerprinting"], answer:0, explain:"<strong>AI-driven automated code generation</strong> lets systems produce working code with minimal human writing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual machine-language programming</b>: that is the older, fully manual approach AI replaces.</span><span class='qd'><b>Physical penetration testing</b>: this concerns physical security tests, not code generation.</span><span class='qd'><b>Honeypot fingerprinting</b>: that is an attacker activity, unrelated to coding.</span>" },
  { id:"D3-095", domain:3, obj:"3.3", diff:"hard", q:"A SOC ingests reports that compare collected data with known threat actor TTPs and provides attribution recommendations linked to ATT&CK and ATLAS. Which automation benefit is most evident for incident analysis?", options:["Automatic deletion of evidence","Faster, framework-grounded attribution to support response","Slower manual correlation","Generation of disinformation"], answer:1, explain:"<strong>Faster, framework-grounded attribution to support response</strong> is the benefit of AI linking data to ATT&CK and ATLAS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Automatic deletion of evidence</b>: attribution preserves and references evidence, not deletes it.</span><span class='qd'><b>Slower manual correlation</b>: AI speeds correlation, not slows it.</span><span class='qd'><b>Generation of disinformation</b>: that is an attacker misuse, not attribution.</span>" },
  { id:"D3-096", domain:3, obj:"3.3", diff:"medium", q:"A team wants AI to develop PowerShell and Python queries to interrogate their SIEM and SOAR during live incidents. What outcome does the source material highlight?", options:["Generating deepfake video evidence","Permanently disabling the SIEM","Speeding up detection and triage of security incidents as they happen","Removing all human analysts"], answer:2, explain:"<strong>Speeding up detection and triage of security incidents as they happen</strong> is the highlighted outcome of AI-generated SIEM and SOAR queries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Permanently disabling the SIEM</b>: AI queries the SIEM rather than disabling it.</span><span class='qd'><b>Generating deepfake video evidence</b>: that is an offensive technique, not triage.</span><span class='qd'><b>Removing all human analysts</b>: AI assists analysts, not replaces them entirely.</span>" },
  { id:"D3-097", domain:3, obj:"3.3", diff:"easy", q:"A new analyst defines automation as using technology and software to accomplish tasks with little to no human interaction. Which example fits this definition?", options:["A SOAR playbook auto-triaging alerts without analyst clicks","A manager hand-writing each incident report","An analyst manually closing every ticket","A technician physically rebooting servers one by one"], answer:0, explain:"<strong>A SOAR playbook auto-triaging alerts without analyst clicks</strong> exemplifies automation with little to no human interaction.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A manager hand-writing each incident report</b>: this is fully manual, not automation.</span><span class='qd'><b>An analyst manually closing every ticket</b>: manual ticket handling is not automation.</span><span class='qd'><b>A technician physically rebooting servers one by one</b>: manual reboots require human interaction throughout.</span>" },
  { id:"D3-098", domain:3, obj:"3.3", diff:"medium", q:"An AI workflow can implement environment changes such as blocking attack traffic by source IP or device during a DoS, but the source warns this must be carefully controlled. What is the main risk if controls are weak?", options:["The firewall becomes immune to all attacks","The AI may make changes when no incident is actually occurring","Logging speeds up automatically","Encryption becomes unnecessary"], answer:1, explain:"<strong>The AI may make changes when no incident is actually occurring</strong>, which is why prescribed-action controls are emphasized.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The firewall becomes immune to all attacks</b>: automation does not make firewalls immune.</span><span class='qd'><b>Logging speeds up automatically</b>: this is not the risk described.</span><span class='qd'><b>Encryption becomes unnecessary</b>: encryption remains necessary regardless.</span>" },
  { id:"D3-099", domain:3, obj:"3.3", diff:"hard", q:"A governance lead argues that even with automated change approvals, a human must verify modifications to the security environment. What is the core justification given in the source material?", options:["AI never makes mistakes once trained","Humans are faster than AI at every task","AI systems cannot be held accountable for their actions","Logging is impossible in CI/CD"], answer:2, explain:"<strong>AI systems cannot be held accountable for their actions</strong>, so humans must remain in the loop to verify changes for compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Humans are faster than AI at every task</b>: AI is often faster; speed is not the justification.</span><span class='qd'><b>AI never makes mistakes once trained</b>: AI can hallucinate and err, which is why oversight is needed.</span><span class='qd'><b>Logging is impossible in CI/CD</b>: logging is in fact required and feasible in CI/CD.</span>" },
  { id:"D3-100", domain:3, obj:"3.3", diff:"medium", q:"A CISO summarizes the value of adopting an AI-assisted security platform. Which combination of benefits does the source material attribute to it?", options:["Automatic generation of deepfakes for defense","Guaranteed zero incidents and no need for staff","Elimination of all logging and oversight","Faster decisions, fewer human errors in repetitive tasks, and support for the software development life cycle"], answer:3, explain:"<strong>Faster decisions, fewer human errors in repetitive tasks, and support for the software development life cycle</strong> are the attributed benefits of AI-assisted platforms.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteed zero incidents and no need for staff</b>: AI assists staff and cannot guarantee zero incidents.</span><span class='qd'><b>Elimination of all logging and oversight</b>: logging and human oversight remain essential.</span><span class='qd'><b>Automatic generation of deepfakes for defense</b>: deepfakes are an offensive misuse, not a defensive platform benefit.</span>" }
);
